/**
 * Teleportation cache boot fan-out test.
 *
 * Validates that {@link PneumaPipeline} fires `MemoClient.configure({enabled:true})`
 * against every station that exposes an HTTP-shaped fetcher when (and only
 * when) `enableTeleportation` is set on the config.
 *
 * The handoff item: production turns must get the cache enabled by default
 * once the operator opts in (`--enable-teleportation` on `pneuma-think`).
 * Stations without the `/memo/configure` route silently 404 — this is the
 * expected shape for the legacy worker build that hasn't shipped the memo
 * surface — so the boot must NOT poison construction on a 404.
 *
 * Coverage:
 *   - configure is called per station with the bench-validated knobs
 *   - omitting enableTeleportation skips the call entirely
 *   - 404 from a station is bucketed as 'skipped', not 'error'
 *   - non-HTTP stations (no endpoint+baseUrl) are bucketed as 'skipped'
 */

import { describe, expect, it } from 'vitest';

import { PneumaPipeline } from '../pipeline_pneuma';
import type { Station } from '../station';
import type { MemoFetcher } from '../memo-client';

interface RecordedCall {
  baseUrl: string;
  path: string;
  method: string;
  body: string;
}

/**
 * Builds a Station-shaped stub with a recording HTTP fetcher. The
 * teleportation boot duck-types via `endpoint.fetch` + `baseUrl`, so this
 * is the minimal surface the boot path needs.
 *
 * `respond` controls the canned response so each test can simulate
 * configure-success / 404 / 500 / network-fail.
 */
function buildHttpStation(opts: {
  baseUrl: string;
  respond: (req: Request) => Response | Promise<Response>;
  recorded: RecordedCall[];
}): Station {
  const fetcher: MemoFetcher = {
    fetch: async (req: Request): Promise<Response> => {
      const url = new URL(req.url);
      const body = req.body ? await req.text() : '';
      opts.recorded.push({
        baseUrl: `${url.protocol}//${url.host}`,
        path: url.pathname,
        method: req.method,
        body,
      });
      return opts.respond(req);
    },
  };

  // Minimal Station-shape stub. We don't exercise any of the inference
  // methods — PneumaPipeline only touches `endpoint`+`baseUrl` during
  // teleportation boot, then the inference methods on demand (which the
  // tests below don't call).
  const stub = {
    startLayer: 0,
    endLayer: 1,
    role: 'entry' as const,
    maxBatchSize: 4,
    endpoint: fetcher,
    baseUrl: opts.baseUrl,
    embedAudio: async () => new Float32Array(0),
    forwardEncoderRange: async () => new Float32Array(0),
    finalizeEncoder: async () => new Float32Array(0),
    encodeStreamingChunk: async () => new Float32Array(0),
    loadAudioContext: async () => undefined as unknown,
    decodeStep: async () => new Float32Array(0),
  };
  return stub as unknown as Station;
}

/**
 * Builds a UDS-style stub WITHOUT `endpoint`/`baseUrl`. The boot duck-type
 * skips it without contacting the wire — this models the StationUds /
 * StationFlow path where there is no HTTP base URL to POST against.
 */
function buildNonHttpStation(): Station {
  const stub = {
    startLayer: 0,
    endLayer: 1,
    role: 'entry' as const,
    maxBatchSize: 8,
    embedAudio: async () => new Float32Array(0),
    forwardEncoderRange: async () => new Float32Array(0),
    finalizeEncoder: async () => new Float32Array(0),
    encodeStreamingChunk: async () => new Float32Array(0),
    loadAudioContext: async () => undefined as unknown,
    decodeStep: async () => new Float32Array(0),
  };
  return stub as unknown as Station;
}

function jsonResponse(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}

/**
 * Fresh-per-call OK response factory. Response bodies are read-once in
 * the Fetch API; a shared Response instance gets its body consumed by
 * the first reader and `.json()` throws on the second. Every responder
 * must mint a new Response per call.
 */
function configureOk(): Response {
  return jsonResponse({
    configured: true,
    stats: { hits: 0, misses: 0, evictions: 0 },
  });
}

describe('PneumaPipeline — teleportation cache boot', () => {
  it('omitting enableTeleportation skips configure entirely', async () => {
    const recorded: RecordedCall[] = [];
    const enc = buildHttpStation({
      baseUrl: 'http://encoder',
      respond: () => configureOk(),
      recorded,
    });
    const dec = buildHttpStation({
      baseUrl: 'http://decoder',
      respond: () => configureOk(),
      recorded,
    });

    const pipeline = new PneumaPipeline({
      encoderStations: [enc],
      decoderStations: [dec],
      // enableTeleportation NOT set
    });

    // The boot promise is null in this branch; teleportationReady() resolves
    // to null without firing any fetch.
    const result = await pipeline.teleportationReady();
    expect(result).toBeNull();
    expect(recorded).toEqual([]);
  });

  it('enableTeleportation fires /memo/configure per HTTP station', async () => {
    const recorded: RecordedCall[] = [];
    const enc = buildHttpStation({
      baseUrl: 'http://encoder.example',
      respond: () => configureOk(),
      recorded,
    });
    const dec = buildHttpStation({
      baseUrl: 'http://decoder.example',
      respond: () => configureOk(),
      recorded,
    });

    const pipeline = new PneumaPipeline({
      encoderStations: [enc],
      decoderStations: [dec],
      enableTeleportation: { tauSquared: 1e-4, maxEntries: 8192 },
    });

    const outcomes = await pipeline.teleportationReady();
    expect(outcomes).not.toBeNull();
    expect(outcomes!.length).toBe(2);

    // Both stations should be marked 'configured'.
    const configured = outcomes!.filter((o) => o.status === 'configured');
    expect(configured.length).toBe(2);

    // configure POST hit each station's /memo/configure with the bench knobs
    // serialized in the wire-snake-case (tau_squared / max_entries).
    expect(recorded.length).toBe(2);
    for (const r of recorded) {
      expect(r.method).toBe('POST');
      expect(r.path).toBe('/memo/configure');
      const parsed = JSON.parse(r.body) as Record<string, unknown>;
      expect(parsed.enabled).toBe(true);
      expect(parsed.tau_squared).toBe(1e-4);
      expect(parsed.max_entries).toBe(8192);
    }
    // Each station was hit exactly once (set instead of array to catch dupes).
    const baseUrls = new Set(recorded.map((r) => r.baseUrl));
    expect(baseUrls.has('http://encoder.example')).toBe(true);
    expect(baseUrls.has('http://decoder.example')).toBe(true);
  });

  it('404 from /memo/configure is bucketed as skipped, not error', async () => {
    const recorded: RecordedCall[] = [];
    // First station 404s (no memo route on this build); second succeeds.
    const enc = buildHttpStation({
      baseUrl: 'http://legacy-encoder',
      respond: () => new Response('not found', { status: 404 }),
      recorded,
    });
    const dec = buildHttpStation({
      baseUrl: 'http://memo-decoder',
      respond: () => configureOk(),
      recorded,
    });

    const pipeline = new PneumaPipeline({
      encoderStations: [enc],
      decoderStations: [dec],
      enableTeleportation: { tauSquared: 1e-4 },
    });

    const outcomes = await pipeline.teleportationReady();
    expect(outcomes).not.toBeNull();

    const byKind = new Map(outcomes!.map((o) => [o.kind, o]));
    expect(byKind.get('encoder')?.status).toBe('skipped');
    expect(byKind.get('decoder')?.status).toBe('configured');
  });

  it('non-HTTP stations (no endpoint+baseUrl) are skipped without contacting the wire', async () => {
    const recorded: RecordedCall[] = [];
    const httpEnc = buildHttpStation({
      baseUrl: 'http://encoder',
      respond: () => configureOk(),
      recorded,
    });
    const udsLikeDec = buildNonHttpStation();

    const pipeline = new PneumaPipeline({
      encoderStations: [httpEnc],
      decoderStations: [udsLikeDec],
      enableTeleportation: { tauSquared: 1e-4, maxEntries: 8192 },
    });

    const outcomes = await pipeline.teleportationReady();
    expect(outcomes).not.toBeNull();
    expect(outcomes!.length).toBe(2);

    const httpOutcome = outcomes!.find((o) => o.kind === 'encoder');
    const udsOutcome = outcomes!.find((o) => o.kind === 'decoder');
    expect(httpOutcome?.status).toBe('configured');
    expect(udsOutcome?.status).toBe('skipped');

    // Only the HTTP station was actually contacted.
    expect(recorded.length).toBe(1);
    expect(recorded[0]!.baseUrl).toBe('http://encoder');
  });

  it('500 server error is bucketed as error (not silently configured)', async () => {
    const recorded: RecordedCall[] = [];
    const enc = buildHttpStation({
      baseUrl: 'http://broken-encoder',
      respond: () => new Response('boom', { status: 500 }),
      recorded,
    });
    const dec = buildHttpStation({
      baseUrl: 'http://decoder',
      respond: () => configureOk(),
      recorded,
    });

    const pipeline = new PneumaPipeline({
      encoderStations: [enc],
      decoderStations: [dec],
      enableTeleportation: { tauSquared: 1e-4 },
    });

    const outcomes = await pipeline.teleportationReady();
    expect(outcomes).not.toBeNull();

    const byKind = new Map(outcomes!.map((o) => [o.kind, o]));
    expect(byKind.get('encoder')?.status).toBe('error');
    expect(byKind.get('decoder')?.status).toBe('configured');
    // The error message should preserve the underlying status for debug.
    expect(byKind.get('encoder')?.error).toContain('500');
  });

  it('configure body omits unset knobs (server-side defaults inherited)', async () => {
    const recorded: RecordedCall[] = [];
    const enc = buildHttpStation({
      baseUrl: 'http://encoder',
      respond: () => configureOk(),
      recorded,
    });

    new PneumaPipeline({
      encoderStations: [enc],
      decoderStations: [enc],
      // No tauSquared / maxEntries — only `enabled: true` should ride.
      enableTeleportation: {},
    });

    // Wait for the fan-out to land before inspecting recorded.
    // (fireMemoConfigure is async; the constructor doesn't await it.)
    await new Promise((r) => setTimeout(r, 0));
    await new Promise((r) => setTimeout(r, 0));

    expect(recorded.length).toBeGreaterThan(0);
    for (const r of recorded) {
      const parsed = JSON.parse(r.body) as Record<string, unknown>;
      expect(parsed.enabled).toBe(true);
      expect('tau_squared' in parsed).toBe(false);
      expect('max_entries' in parsed).toBe(false);
    }
  });
});
